from math import ceil, sqrt, log

def mod_expo(n, p, m):
	"""find (n^p)%m"""
	result = 1
	while p != 0:
		if p%2 == 1:
			result = (result * n)%m
		p //= 2
		n = (n * n)%m
	return result

def is_square(n):
	return int(sqrt(n))*int(sqrt(n)) == n

def find_div(n):
	d = []
	for i in range(2, int(sqrt(n))+1):
		if n%i == 0:
			if i*i != n:
				d.append(i)
				d.append(n/i)
			else:
				d.append(i)
	return d				

def find_x(n):
	d = find_div(2*n)
	for div in d:
		x2 = div*(div + 2*n)
		if is_square(x2):
			return sqrt(x2)
	return -1

def find_base_side(n):
	squares = [x*x for x in range(ceil(sqrt(n)))]
	for i in range(len(squares)):
		for j in range(len(squares)):
			if squares[i] + squares[j] == n*n:
				return squares[i]
	return -1

def str_add(n):
	n = list(n)
	for i in range(1, len(n)+1):
		if n[-i] == '9':
			n[-i] = '0'
		else:
			n[-i] = int(int(n[-i]) + 1)
			break
	n = str(n)
	return n	

def str_sub(n):
	n = list(n)
	for i in range(1, len(n)+1):
		if n[-i] == '0':
			n[-i] = '9'
		else:
			n[-i] = int(int(n[-i]) - 1)
			break
	n = str(n)
	return n		

